#!/usr/bin/env bash\nset -euo pipefail\n\n# РЈСЃС‚Р°РЅРѕРІРєР° РјРёРЅРёРјР°Р»СЊРЅС‹С… С‚РµСЂРјРёРЅР°Р»СЊРЅС‹С… AI-РёРЅСЃС‚СЂСѓРјРµРЅС‚РѕРІ РґР»СЏ СЂР°Р±РѕС‚С‹ СЃ Ollama.\n# РЎСЋРґР° РІС…РѕРґРёС‚ СѓСЃС‚Р°РЅРѕРІРєР° СѓС‚РёР»РёС‚-Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№ Рё СЂР°Р·РјРµС‰РµРЅРёРµ `ai-chat` РІ PATH.\n\nif [[ $EUID -ne 0 ]]; then\n  echo "РџРѕР¶Р°Р»СѓР№СЃС‚Р°, Р·Р°РїСѓСЃС‚РёС‚Рµ СЌС‚РѕС‚ СЃРєСЂРёРїС‚ СЃ sudo РёР»Рё РѕС‚ root."\n  exit 1\nfi\n\necho "[install-terminal-ai] РЈСЃС‚Р°РЅРѕРІРєР° Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№..."\napt-get update -y\nDEBIAN_FRONTEND=noninteractive apt-get install -y curl ca-certificates jq\n\nSCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"\n\necho "[install-terminal-ai] РЈСЃС‚Р°РЅРѕРІРєР° ai-chat РІ /usr/local/bin..."\ninstall -m 0755 "${SCRIPT_DIR}/ai-chat" /usr/local/bin/ai-chat\n\necho "[install-terminal-ai] Р“РѕС‚РѕРІРѕ. РСЃРїРѕР»СЊР·СѓР№С‚Рµ РєРѕРјР°РЅРґСѓ: ai-chat \"РІР°С€ Р·Р°РїСЂРѕСЃ\""\n\n